using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

// Train the model at startup so it is always fresh
using (var loggerFactory = LoggerFactory.Create(b => b.AddConsole()))
{
    TicketModelTrainer.TrainAndSave(dataPath, modelPath, loggerFactory.CreateLogger("ModelTrainer"));
}

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapPost("/api/tickets/classify", (
    TicketRequest request,
    PredictionEnginePool<TicketInput, TicketPrediction> pool) =>
{
    var input = new TicketInput
    {
        Subject = request.Subject,
        Description = request.Description,
        Priority = request.Priority
    };

    var prediction = pool.Predict(input);

    string[] labels = ["Billing", "General", "Technical"];
    var confidence = new Dictionary<string, float>();
    for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        confidence[labels[i]] = prediction.Score[i];

    return Results.Ok(new TicketResponse
    {
        PredictedCategory = prediction.Category,
        Confidence = confidence
    });
});

app.Run();

